class Knoten {
    int wert;
    Knoten links, rechts;
    Knoten(int wert) { this.wert = wert; }
}

Knoten einfuegenRek(Knoten k, int wert) {
    if (k == null) return new Knoten(wert);
    if (wert < k.wert) {
        k.links = einfuegenRek(k.links, wert);
    } else {
        k.rechts = einfuegenRek(k.rechts, wert);
    }
    return k;
}

void inorder(Knoten k) {
    if (k == null) return;
    inorder(k.links);
    System.out.print(k.wert + " ");
    inorder(k.rechts);
}

